31	/*! \file
32	    \brief Statically sized array of elements that accommodates all CUTLASS-supported numeric types
33	           and is safe to use in a union.
34	*/
35	
36	#pragma once
37	#include "cutlass/cutlass.h"
38	#include "cutlass/functional.h"
39	#include "cutlass/numeric_types.h"
