41	namespace cutlass {
42	
43	////////////////////////////////////////////////////////////////////////////////////////////////////
44	
45	/// Statically sized array for any data type
46	template <
47	  typename T,
48	  int N,
49	  bool RegisterSized = sizeof_bits<T>::value >= 32
50	>
51	struct Array;
52	
53	namespace detail {
54	
55	template<class T>
56	struct is_Array : platform::false_type {};
57	
58	template <
59	  typename T,
60	  int N,
61	  bool RegisterSized
62	>
63	struct is_Array<Array<T, N, RegisterSized> > : platform::true_type {};
64	
65	template<typename T>
66	constexpr bool is_Array_v = is_Array<T>::value;
67	
68	} // namespace detail
69	
70	////////////////////////////////////////////////////////////////////////////////////////////////////
71	
72	/// Defines the size of an Array<> in bits
73	template <typename T, int N, bool RegisterSized>
74	struct sizeof_bits<Array<T, N, RegisterSized> > {
75	  static constexpr int value = sizeof(Array<T, N, RegisterSized>) * 8;
76	};
77	
78	////////////////////////////////////////////////////////////////////////////////////////////////////
79	
80	/// Returns true if the argument is a power of 2
81	CUTLASS_HOST_DEVICE
82	constexpr bool ispow2(unsigned x) {
83	  return x && (!(x & (x - 1)));
84	}
85	
86	////////////////////////////////////////////////////////////////////////////////////////////////////
87	
88	/// Returns the largest power of two not greater than the argument.
89	CUTLASS_HOST_DEVICE
90	constexpr unsigned floor_pow_2(unsigned x) {
91	  return (x == 0 || ispow2(x)) ? x : ((floor_pow_2(x >> 1)) << 1);
92	}
93	
94	////////////////////////////////////////////////////////////////////////////////////////////////////
95	
96	/// Statically sized array for any data type
97	template <
98	  typename T,
99	  int N
100	>
101	struct Array<T, N, true> {
102	
103	  /// Storage type
104	  using Storage = T;
105	
106	  /// Element type
107	  using Element = T;
108	
109	  /// Number of storage elements
110	  //static std::size_t const kStorageElements = N;
111	  static constexpr size_t kStorageElements = N;
112	
113	  /// Number of logical elements
114	  static constexpr size_t kElements = N;
115	
116	  //
117	  // C++ standard members
118	  //
119	
120	  typedef T value_type;
121	  typedef size_t size_type;
122	  typedef ptrdiff_t difference_type;
123	  typedef value_type &reference;
124	  typedef value_type const & const_reference;
125	  typedef value_type *pointer;
126	  typedef value_type const * const_pointer;
127	
128	  //
129	  // Iterators
130	  //
131	
132	  /// Bidirectional iterator over elements
133	  class iterator {
134	
135	    /// Pointer to object
136	    T *ptr_;
137	
138	  public:
139	
140	    CUTLASS_HOST_DEVICE
141	    iterator(): ptr_(nullptr) { }
142	
143	    CUTLASS_HOST_DEVICE
144	    iterator(T *_ptr): ptr_(_ptr) { }
145	
146	    CUTLASS_HOST_DEVICE
147	    iterator &operator++() {
148	      ++ptr_;
149	      return *this;
150	    }
151	
152	    CUTLASS_HOST_DEVICE
153	    iterator &operator--() {
154	      --ptr_;
155	      return *this;
156	    }
157	
158	    CUTLASS_HOST_DEVICE
159	    iterator operator++(int) {
160	      iterator ret(*this);
161	      ++ptr_;
162	      return ret;
163	    }
164	
165	    CUTLASS_HOST_DEVICE
166	    iterator operator--(int) {
167	      iterator ret(*this);
168	      --ptr_;
169	      return ret;
170	    }
171	
172	    CUTLASS_HOST_DEVICE
173	    T &operator*() const {
174	      return *ptr_;
175	    }
176	
177	    CUTLASS_HOST_DEVICE
178	    bool operator==(iterator const &other) const {
179	      return ptr_ == other.ptr_;
180	    }
181	
182	    CUTLASS_HOST_DEVICE
183	    bool operator!=(iterator const &other) const {
184	      return ptr_ != other.ptr_;
185	    }
186	  };
187	
188	  /// Bidirectional constant iterator over elements
189	  class const_iterator {
190	
191	    /// Pointer to object
192	    const T *ptr_;
193	
194	  public:
195	
196	    CUTLASS_HOST_DEVICE
197	    const_iterator(): ptr_(nullptr) { }
198	
199	    CUTLASS_HOST_DEVICE
200	    const_iterator(T const *_ptr): ptr_(_ptr) { }
201	
202	    CUTLASS_HOST_DEVICE
203	    const_iterator &operator++() {
204	      ++ptr_;
205	      return *this;
206	    }
207	
208	    CUTLASS_HOST_DEVICE
209	    const_iterator &operator--() {
210	      --ptr_;
211	      return *this;
212	    }
213	
214	    CUTLASS_HOST_DEVICE
215	    const_iterator operator++(int) {
216	      const_iterator ret(*this);
217	      ++ptr_;
218	      return ret;
219	    }
220	
221	    CUTLASS_HOST_DEVICE
222	    const_iterator operator--(int) {
223	      const_iterator ret(*this);
224	      --ptr_;
225	      return ret;
226	    }
227	
228	    CUTLASS_HOST_DEVICE
229	    T const &operator*() const {
230	      return *ptr_;
231	    }
232	
233	    CUTLASS_HOST_DEVICE
234	    bool operator==(const_iterator const &other) const {
235	      return ptr_ == other.ptr_;
236	    }
237	
238	    CUTLASS_HOST_DEVICE
239	    bool operator!=(const_iterator const &other) const {
240	      return ptr_ != other.ptr_;
241	    }
242	  };
243	
244	  /// Bidirectional iterator over elements
245	  class reverse_iterator {
246	
247	    /// Pointer to object
248	    T *ptr_;
249	
250	  public:
251	
252	    CUTLASS_HOST_DEVICE
253	    reverse_iterator(): ptr_(nullptr) { }
254	
255	    CUTLASS_HOST_DEVICE
256	    reverse_iterator(T *_ptr): ptr_(_ptr) { }
257	
258	    CUTLASS_HOST_DEVICE
259	    reverse_iterator &operator++() {
260	      --ptr_;
261	      return *this;
262	    }
263	
264	    CUTLASS_HOST_DEVICE
265	    reverse_iterator &operator--() {
266	      ++ptr_;
267	      return *this;
268	    }
269	
270	    CUTLASS_HOST_DEVICE
271	    reverse_iterator operator++(int) {
272	      iterator ret(*this);
273	      --ptr_;
274	      return ret;
275	    }
276	
277	    CUTLASS_HOST_DEVICE
278	    reverse_iterator operator--(int) {
279	      iterator ret(*this);
280	      ++ptr_;
281	      return ret;
282	    }
283	
284	    CUTLASS_HOST_DEVICE
285	    T &operator*() const {
286	      return *(ptr_ - 1);
287	    }
288	
289	    CUTLASS_HOST_DEVICE
290	    bool operator==(reverse_iterator const &other) const {
291	      return ptr_ == other.ptr_;
292	    }
293	
294	    CUTLASS_HOST_DEVICE
295	    bool operator!=(reverse_iterator const &other) const {
296	      return ptr_ != other.ptr_;
297	    }
298	  };
299	
300	  /// Bidirectional constant iterator over elements
301	  class const_reverse_iterator {
302	
303	    /// Pointer to object
304	    T const *ptr_;
305	
306	  public:
307	
308	    CUTLASS_HOST_DEVICE
309	    const_reverse_iterator(): ptr_(nullptr) { }
310	
311	    CUTLASS_HOST_DEVICE
312	    const_reverse_iterator(T const *_ptr): ptr_(_ptr) { }
313	
314	    CUTLASS_HOST_DEVICE
315	    const_reverse_iterator &operator++() {
316	      --ptr_;
317	      return *this;
318	    }
319	
320	    CUTLASS_HOST_DEVICE
321	    const_reverse_iterator &operator--() {
322	      ++ptr_;
323	      return *this;
324	    }
325	
326	    CUTLASS_HOST_DEVICE
327	    const_reverse_iterator operator++(int) {
328	      const_reverse_iterator ret(*this);
329	      --ptr_;
330	      return ret;
331	    }
332	
333	    CUTLASS_HOST_DEVICE
334	    const_reverse_iterator operator--(int) {
335	      const_reverse_iterator ret(*this);
336	      ++ptr_;
337	      return ret;
338	    }
339	
340	    CUTLASS_HOST_DEVICE
341	    T const &operator*() const {
342	      return *(ptr_ - 1);
343	    }
344	
345	    CUTLASS_HOST_DEVICE
346	    bool operator==(const_iterator const &other) const {
347	      return ptr_ == other.ptr_;
348	    }
349	
350	    CUTLASS_HOST_DEVICE
351	    bool operator!=(const_iterator const &other) const {
352	      return ptr_ != other.ptr_;
353	    }
354	  };
355	
356	  /// Internal storage
357	  Storage storage[kElements];
358	
359	  /// Efficient clear method
360	  CUTLASS_HOST_DEVICE
361	  void clear() {
362	    fill(T(0));
363	  }
364	
365	  CUTLASS_HOST_DEVICE
366	  reference at(size_type pos) {
367	    return reinterpret_cast<reference>(storage[pos]);
368	  }
369	
370	  CUTLASS_HOST_DEVICE
371	  const_reference at(size_type pos) const {
372	    return reinterpret_cast<const_reference>(storage[pos]);
373	  }
374	
375	  CUTLASS_HOST_DEVICE
376	  reference operator[](size_type pos) {
377	    return reinterpret_cast<reference>(storage[pos]);
378	  }
379	
380	  CUTLASS_HOST_DEVICE
381	  const_reference operator[](size_type pos) const {
382	    return reinterpret_cast<const_reference>(storage[pos]);
383	  }
384	
385	  CUTLASS_HOST_DEVICE
386	  reference front() {
387	    return reinterpret_cast<reference>(storage[0]);
388	  }
389	
390	  CUTLASS_HOST_DEVICE
391	  const_reference front() const {
392	    return reinterpret_cast<const_reference>(storage[0]);
393	  }
394	
395	  CUTLASS_HOST_DEVICE
396	  reference back() {
397	    return reinterpret_cast<reference>(storage[kStorageElements - 1]);
398	  }
399	
400	  CUTLASS_HOST_DEVICE
401	  const_reference back() const {
402	    return reinterpret_cast<const_reference>(storage[kStorageElements - 1]);
403	  }
404	
405	  CUTLASS_HOST_DEVICE
406	  pointer data() {
407	    return reinterpret_cast<pointer>(storage);
408	  }
409	
410	  CUTLASS_HOST_DEVICE
411	  const_pointer data() const {
412	    return reinterpret_cast<const_pointer>(storage);
413	  }
414	  
415	  CUTLASS_HOST_DEVICE
416	  pointer raw_data() {
417	    return reinterpret_cast<pointer>(storage);
418	  }
419	
420	  CUTLASS_HOST_DEVICE
421	  const_pointer raw_data() const {
422	    return reinterpret_cast<const_pointer>(storage);
423	  }
424	
425	
426	  CUTLASS_HOST_DEVICE
427	  constexpr bool empty() const {
428	    return !kElements;
429	  }
430	
431	  CUTLASS_HOST_DEVICE
432	  constexpr size_type size() const {
433	    return kElements;
434	  }
435	
436	  CUTLASS_HOST_DEVICE
437	  constexpr size_type max_size() const {
438	    return kElements;
439	  }
440	
441	  CUTLASS_HOST_DEVICE
442	  void fill(T const &value) {
443	    CUTLASS_PRAGMA_UNROLL
444	    for (int i = 0; i < int(kElements); ++i) {
445	      storage[i] = static_cast<Storage>(value);
446	    }
447	  }
448	
449	  CUTLASS_HOST_DEVICE
450	  iterator begin() {
451	    return iterator(storage);
452	  }
453	
454	  CUTLASS_HOST_DEVICE
455	  const_iterator begin() const {
456	    return cbegin();
457	  }
458	
459	  CUTLASS_HOST_DEVICE
460	  const_iterator cbegin() const {
461	    return const_iterator(storage);
462	  }
463	
464	  CUTLASS_HOST_DEVICE
465	  iterator end() {
466	    return iterator(reinterpret_cast<pointer>(storage + kStorageElements));
467	  }
468	
469	  CUTLASS_HOST_DEVICE
470	  const_iterator end() const {
471	    return cend();
472	  }
473	
474	  CUTLASS_HOST_DEVICE
475	  const_iterator cend() const {
476	    return const_iterator(reinterpret_cast<const_pointer>(storage + kStorageElements));
477	  }
478	
479	  CUTLASS_HOST_DEVICE
