482	  }
483	
484	  CUTLASS_HOST_DEVICE
485	  const_reverse_iterator rbegin() const {
486	    return crbegin();
487	  }
488	
489	  CUTLASS_HOST_DEVICE
490	  const_reverse_iterator crbegin() const {
491	    return const_reverse_iterator(reinterpret_cast<const_pointer>(storage + kStorageElements));
492	  }
493	
494	  CUTLASS_HOST_DEVICE
495	  reverse_iterator rend() {
496	    return reverse_iterator(reinterpret_cast<pointer>(storage));
497	  }
498	
499	  CUTLASS_HOST_DEVICE
500	  const_reverse_iterator rend() const {
501	    return crend();
502	  }
503	
504	  CUTLASS_HOST_DEVICE
505	  const_reverse_iterator crend() const {
506	    return const_reverse_iterator(reinterpret_cast<const_pointer>(storage));
507	  }
508	
509	  //
510	  // Comparison operators
511	  //
512	
513	};
