548	
549	template <typename T, int N>
550	struct absolute_value_op< Array<T, N> > {
551	
552	  CUTLASS_HOST_DEVICE
553	  Array<T, N> operator()(Array<T, N> const &lhs) const {
554	
555	    Array<T, N> result;
556	    absolute_value_op<T> scalar_op;
557	
558	    CUTLASS_PRAGMA_UNROLL
559	    for (int i = 0; i < N; ++i) {
560	      result[i] = scalar_op(lhs[i]);
561	    }
562	
563	    return result;
564	  }
565	};
